@@ -0,0 +1,18 @@
+{
+  "id": "017_type_affinity_edge",
+  "description": "Type affinity edge coercions for NUMERIC/TEXT/INTEGER columns",
+  "ops": [
+    { "op": "open", "path": ":memory:" },
+    { "op": "exec", "sql": "CREATE TABLE q1(a NUMERIC, b TEXT, c INTEGER)" },
+    { "op": "exec", "sql": "INSERT INTO q1 VALUES('3.0e+5', 123, '0042')" },
+    {
+      "op": "query",
+      "sql": "SELECT typeof(a), a, typeof(b), b, typeof(c), c FROM q1",
+      "expect": {
+        "rows": [["integer", "300000", "text", "123", "integer", "42"]],
+        "ordered": true
+      }
+    }
+  ],
+  "fsqlite_modes": ["compatibility", "native"]
+}

@@ -0,0 +1,13 @@
+{
+  "id": "018_collation_ascii_unicode_nocase",
+  "description": "NOCASE collation is ASCII-insensitive but Unicode-sensitive",
+  "ops": [
+    { "op": "open", "path": ":memory:" },
+    {
+      "op": "query",
+      "sql": "SELECT 'a' = 'A' COLLATE NOCASE, 'æ' = 'Æ' COLLATE NOCASE",
+      "expect": { "rows": [["1", "0"]], "ordered": true }
+    }
+  ],
+  "fsqlite_modes": ["compatibility", "native"]
+}

@@ -0,0 +1,13 @@
+{
+  "id": "020_integer_overflow_semantics",
+  "description": "64-bit integer arithmetic overflow promotes expression results to REAL",
+  "ops": [
+    { "op": "open", "path": ":memory:" },
+    {
+      "op": "query",
+      "sql": "SELECT typeof(9223372036854775807 + 1), typeof(-9223372036854775808 - 1)",
+      "expect": { "rows": [["real", "real"]], "ordered": true }
+    }
+  ],
+  "fsqlite_modes": ["compatibility", "native"]
+}
